import { Task, Team, User } from './types';

// --- In-memory "Database" ---
const users: User[] = [
  {
    id: 'user-1',
    name: 'Alice Admin',
    teamMemberships: [{ teamId: 'team-1', role: 'admin' }],
  },
  {
    id: 'user-2',
    name: 'Bob Member',
    teamMemberships: [{ teamId: 'team-1', role: 'member' }],
  },
  {
    id: 'user-3',
    name: 'Charlie Admin',
    teamMemberships: [{ teamId: 'team-2', role: 'admin' }],
  },
];

const teams: Team[] = [
  { id: 'team-1', name: 'Alpha Team' },
  { id: 'team-2', name: 'Beta Team' },
  { id: 'team-3', name: 'Gamma Team' },
];

const tasks: Task[] = [
  {
    id: 'task-1',
    title: 'Implement login feature',
    description: 'Develop the user authentication system.',
    teamId: 'team-1',
    assignedTo: 'user-2',
    status: 'in-progress',
  },
  {
    id: 'task-2',
    title: 'Design database schema',
    description: 'Create the initial database structure.',
    teamId: 'team-1',
    assignedTo: 'user-1',
    status: 'pending',
  },
  {
    id: 'task-3',
    title: 'Setup CI/CD pipeline',
    description: 'Configure automated build and deployment.',
    teamId: 'team-2',
    assignedTo: 'user-3',
    status: 'pending',
  },
];

// --- Database Access Functions ---

export const getUserById = (id: string): User | undefined => {
  return users.find((u) => u.id === id);
};

export const getTeamById = (id: string): Team | undefined => {
  return teams.find((t) => t.id === id);
};

export const getTaskById = (id: string): Task | undefined => {
  return tasks.find((t) => t.id === id);
};

export const updateTask = (updatedTask: Task): Task | undefined => {
  const index = tasks.findIndex((t) => t.id === updatedTask.id);
  if (index !== -1) {
    tasks[index] = { ...tasks[index], ...updatedTask };
    return tasks[index];
  }
  return undefined;
};
```

