// --- Simple Event Emitter Simulation ---
type EventName = 'task.transferred';

interface TaskTransferredEvent {
  taskId: string;
  oldTeamId: string;
  newTeamId: string;
  transferredByUserId: string;
  timestamp: Date;
}

type EventPayload = TaskTransferredEvent;

type EventListener = (payload: EventPayload) => void;

const listeners: Map<EventName, EventListener[]> = new Map();

export const emit = (eventName: EventName, payload: EventPayload) => {
  const eventListeners = listeners.get(eventName);
  if (eventListeners) {
    console.log(`[EVENT] Emitting '${eventName}' with payload:`, payload);
    eventListeners.forEach((listener) => listener(payload));
  }
};

export const on = (eventName: EventName, listener: EventListener) => {
  if (!listeners.has(eventName)) {
    listeners.set(eventName, []);
  }
  listeners.get(eventName)?.push(listener);
};

// Example listener (for demonstration/logging)
on('task.transferred', (event) => {
  console.log(
    `[LOG] Task ${event.taskId} transferred from ${event.oldTeamId} to ${event.newTeamId} by ${event.transferredByUserId} at ${event.timestamp.toISOString()}`
  );
});
