import { Context, Next } from 'hono';
import { AppContext, User } from '../types';
import { getUserById } from '../db';

// This is a simplified auth middleware. In a real app, it would
// parse tokens, verify sessions, etc. For this exercise, we'll
// just assume a 'x-user-id' header is present.
export const authMiddleware = async (c: Context<AppContext>, next: Next) => {
  const userId = c.req.header('x-user-id');

  if (!userId) {
    return c.json({ error: 'Authentication required: x-user-id header missing' }, 401);
  }

  const user: User | undefined = getUserById(userId);

  if (!user) {
    return c.json({ error: 'Authentication failed: User not found' }, 401);
  }

  // Attach the user object to the Hono context for later use
  c.set('user', user);
  await next();
};
