```aether:src/routes/tasks/transfer.ts
import { Hono } from 'hono';
import { AppContext } from '../../types';
import { getTaskById, getTeamById, updateTask } from '../../db';
import { authMiddleware } from '../../middleware/auth';
import { emit } from '../../events';

// Define the Hono app with our custom context
const tasksRouter = new Hono<AppContext>();

tasksRouter.put('/:taskId/transfer', authMiddleware, async (c) => {
  const { taskId } = c.req.param();
  const currentUser = c.get('user'); // Injected by authMiddleware

  const { sourceTeamId, targetTeamId } = await c.req.json();

  // 1. Validate input
  if (!sourceTeamId || !targetTeamId) {
    return c.json({ error: 'Missing sourceTeamId or targetTeamId in request body' }, 400);
  }

  if (sourceTeamId === targetTeamId) {
    return c.json({ error: 'Cannot transfer a task to its current team' }, 400);
  }

  // 2. Check if task exists
  const task = getTaskById(taskId);
  if (!task) {
    return c.json({ error: `Task with ID '${taskId}' not found` }, 404);
  }

  // 3. Verify task belongs to the source team
  if (task.teamId !== sourceTeamId) {
    return c.json(
      {
        error: `Task '${taskId}' does not belong to source team '${sourceTeamId}'. It belongs to '${task.teamId}'.`,
      },
      400
    );
  }

  // 4. Check if source and target teams exist
  const sourceTeam = getTeamById(sourceTeamId);
  const targetTeam = getTeamById(targetTeamId);

  if (!sourceTeam) {
    return c.json({ error: `Source team with ID '${sourceTeamId}' not found` }, 404);
  }
  if (!targetTeam) {
    return c.json({ error: `Target team with ID '${targetTeamId}' not found` }, 404);
  }

  // 5. Check if the current user is an admin of the source team
  const isSourceTeamAdmin = currentUser.teamMemberships.some(
    (membership) => membership.teamId === sourceTeamId && membership.role === 'admin'
  );

  if (!isSourceTeamAdmin) {
    return c.json(
      { error: `User '${currentUser.id}' is not an admin of source team '${sourceTeamId}'` },
      403
    );
  }

  // 6. Perform the transfer
  const oldTeamId = task.teamId;
  task.teamId = targetTeamId; // Update the task's teamId

  const updatedTask = updateTask(task);

  if (!updatedTask) {
    // This should ideally not happen if getTaskById found it, but good for robustness
    return c.json({ error: 'Failed to update task' }, 500);
  }

  // 7. Emit task.transferred event
  emit('task.transferred', {
    taskId: updatedTask.id,
    oldTeamId: oldTeamId,
    newTeamId: updatedTask.teamId,
    transferredByUserId: currentUser.id,
    timestamp: new Date(),
  });

  // 8. Respond with success
  return c.json({ message: 'Task transferred successfully', task: updatedTask }, 200);
});

export default tasksRouter;
```

